import{_ as a,c as t,o as i,ag as n}from"./chunks/framework.DPDPlp3K.js";const d=JSON.parse('{"title":"Subscriptions and licenses","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions.md","filePath":"subscriptions.md","lastUpdated":1773350992000}'),s={name:"subscriptions.md"};function o(r,e,l,c,u,p){return i(),t("div",null,e[0]||(e[0]=[n('<h1 id="subscriptions-and-licenses" tabindex="-1">Subscriptions and licenses <a class="header-anchor" href="#subscriptions-and-licenses" aria-label="Permalink to &quot;Subscriptions and licenses&quot;">​</a></h1><p>All public repositories and personal private repositories can use Reviewable free of charge forever. A subscription or license is required for private organizational repositories. Subscriptions are used on <code>reviewable.io</code>, while licenses are needed for managed or self-hosted enterprise instances.</p><h2 id="subscriptions" tabindex="-1">Subscriptions <a class="header-anchor" href="#subscriptions" aria-label="Permalink to &quot;Subscriptions&quot;">​</a></h2><p>The Subscription section of the <a href="https://reviewable.io/admin" target="_blank" rel="noreferrer">Admin Center</a> displays the current subscription or trial status of the organization selected from the dropdown at the top of the page.</p><p>Every organization gets a 30 day free trial of the Business plan, which requires no credit card. Any organization member can start a trial from any private review page, or from the Subscription section in the Admin Center. If the button isn&#39;t showing, then you&#39;re already in the middle of a trial, have recently completed one, or have a current subscription.</p><p>Any organization member can start a new subscription; by doing so, they will become the organization&#39;s <a href="#billing-manager">billing manager</a>. Available plans will be listed for organizations that do not have a current subscription. You can compare plans, add contributors, and click <strong>subscribe</strong> to begin the checkout process. More on this in the <a href="#selecting-a-plan">Selecting a plan</a> section.</p><p>For organizations that are already subscribed, plan details and a <strong>Manage Billing</strong> button will be visible to organization owners and the billing manager.</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>OAuth app restrictions may entirely block Reviewable from an organization. Learn more in the <a href="./registration#oauth-restrictions">OAuth app access restrictions</a> section in the Registration chapter.</p></div><h3 id="billing-manager" tabindex="-1">Billing manager <a class="header-anchor" href="#billing-manager" aria-label="Permalink to &quot;Billing manager&quot;">​</a></h3><p>For organizations with an active subscription, plan details and a <strong>Manage Billing</strong> button are visible to organization owners and the billing manager. Any organization member can start a subscription, and the member who does so becomes the billing manager until they either leave the organization or the role is reassigned via the <strong>Delegate subscription management to</strong> dropdown. Organization owners can always manage the subscription.</p><h3 id="selecting-a-plan" tabindex="-1">Selecting a plan <a class="header-anchor" href="#selecting-a-plan" aria-label="Permalink to &quot;Selecting a plan&quot;">​</a></h3><p>You can select a plan that best suits your organization as well as the number of contributors to purchase the plan for. We count each distinct PR author during a calendar month as a contributor, at the time a review is created and linked to the PR. Once a review has been created, any number of people can view it and participate.</p><p>If a PR causes you to exceed your plan&#39;s contributor quota, both the subscriber and the person who connected the affected repo will be immediately notified by email. Reviewable won&#39;t create reviews for PRs created by additional authors until you upgrade your subscription — or the contributor count resets at the beginning of the next month.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you exceed your plan&#39;s quota, Reviewable will continue updating all previously created reviews and keep creating reviews for contributors that were already counted this month.</p></div><p>You can change or cancel your plan at any time through the <strong>Manage billing</strong> button, which takes you to the Stripe billing portal. If you change your plan during the billing cycle, the new plan (if any) takes effect immediately and fees are prorated which results either in a credit being applied to future invoices, or in additional fees to be charged today. There are no refunds.</p><h3 id="managing-the-scope-of-your-subscription" tabindex="-1">Managing the scope of your subscription <a class="header-anchor" href="#managing-the-scope-of-your-subscription" aria-label="Permalink to &quot;Managing the scope of your subscription&quot;">​</a></h3><p>By default, a subscription covers all reviews in a single organization. Optionally, you can restrict or expand this scope.</p><p>To restrict access to your Reviewable subscription, simply designate a contributor team using the <strong>Limit contributors to members of</strong> dropdown. Only PRs from team members can be submitted for review, even if others outside the team create PRs in a connected repository. Establishing a team is one approach to ensure that you won&#39;t exceed the contributor maximum for your subscription.</p><p>On the other hand, if your company&#39;s repos are distributed over multiple GitHub organizations (as is sometimes the case for consulting companies), you can specify extra organizations to be covered (if your plan allows it) using the <strong>Cover reviews in additional organizations</strong> dropdown. In this situation, a person who creates reviews in any of the subscription&#39;s organizations counts as a single contributor — so this may be a less expensive alternative to maintaining separate subscriptions.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Restricting an organization to a team and extending it to other organizations are mutually exclusive.</p></div><h3 id="canceling-a-subscription" tabindex="-1">Canceling a subscription <a class="header-anchor" href="#canceling-a-subscription" aria-label="Permalink to &quot;Canceling a subscription&quot;">​</a></h3><p>To cancel a subscription, click the <strong>Manage Billing</strong> button to access the Stripe billing portal and then click <strong>Cancel subscription</strong>. Only organization owners and the <a href="#billing-manager">billing manager</a> can do this. If this is not possible or convenient, please get in touch with <a href="mailto:support@reviewable.io" target="_blank" rel="noreferrer">support</a> and we&#39;ll help you out.</p><p>You can change or cancel a subscription at any time with immediate effect, but there will be no refunds or proration of fees. If you cancel, previously created reviews will continue to be accessible and synchronized with GitHub. However, you&#39;ll no longer have the ability to create new reviews.</p><h2 id="licenses" tabindex="-1">Licenses <a class="header-anchor" href="#licenses" aria-label="Permalink to &quot;Licenses&quot;">​</a></h2><p>On an enterprise instance, the license administrator you selected when signing up and any GitHub Enterprise Server instance administrators will be able to check the license details in a panel at the top of the Admin Center. The details include the number of licensed seats, how many are currently in use, the organization(s) the license is constrained to (if any), and the license&#39;s expiry date.</p><p>You can click on the allocated seat count to view the users assigned licensed seats, and guest seats if any are present. Seats are allocated when a user signs in, and released automatically 90 days after a user&#39;s last interaction with Reviewable. You cannot release seats manually.</p><h3 id="team-constraints" tabindex="-1">Team constraints <a class="header-anchor" href="#team-constraints" aria-label="Permalink to &quot;Team constraints&quot;">​</a></h3><p>If desired, you can limit the users who will be able to obtain seats on your instance. This can be useful in larger organizations where Reviewable is only intended for use by a specific team or department, and you don&#39;t want other employees accidentally taking up seats that are needed for the intended users. (By default, any GitHub user can sign in and occupy a seat, or, for an organization-constrained license, any member of said organizations.)</p><p>To turn on team constraints, enter one or more fully-qualified team slugs in the <strong>Limit contributors to members of</strong> field in the organization&#39;s Subscription section in the Admin Center. Only users who are a member of at least one of these teams will be able to obtain a seat. Users with currently assigned seats will <em>not</em> be evicted even if they&#39;re not a team member, but won&#39;t be able to renew their seat once it expires.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The designated license administrator is always allowed to grab a seat so they can&#39;t accidentally lock themselves out.</p></div><h3 id="guest-passes" tabindex="-1">Guest passes <a class="header-anchor" href="#guest-passes" aria-label="Permalink to &quot;Guest passes&quot;">​</a></h3><p>If the license is out of available seats, or team constraints are on and a user signing in is not a member (but otherwise a valid user for the license), they&#39;ll be given a full-access guest pass instead. A guest pass lasts for two weeks and doesn&#39;t take up a license seat, but once it runs out the user will be signed out and unable to sign back in until a seat becomes available / they&#39;re a team member or eligible for a guest pass again (every 90 days). While on a guest pass, every page will display a banner encouraging the user to request access to a licensed seat:</p><blockquote><p>You&#39;ve been allocated a temporary guest seat that will expire in N days. Please contact your organization administrator to obtain a permanent one.</p></blockquote><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><p>On Reviewable Enterprise instances, if enabled by the admin, license information and team constraints can be managed via a <a href="https://github.com/Reviewable/Reviewable/blob/master/enterprise/api.md" target="_blank" rel="noreferrer">REST API</a>.</p>',35)]))}const b=a(s,[["render",o]]);export{d as __pageData,b as default};
